mapper.select:
SELECT oi.*, p.thumbnail_url, p.sale_price, sk.sku_code, oi1.opt_item_nm AS opt_item_nm_1, oi2.opt_item_nm AS opt_item_nm_2, cd_is.code_label AS order_item_status_cd_nm, cd_dc.code_label AS dliv_courier_cd_nm FROM od_order_item oi LEFT JOIN pd_prod p ON p.prod_id = oi.prod_id LEFT JOIN pd_prod_sku sk ON sk.sku_id = oi.sku_id LEFT JOIN pd_prod_opt_item oi1 ON oi1.opt_item_id = oi.opt_item_id_1 LEFT JOIN pd_prod_opt_item oi2 ON oi2.opt_item_id = oi.opt_item_id_2 LEFT JOIN sy_code cd_is ON cd_is.code_grp = 'ORDER_ITEM_STATUS' AND cd_is.code_value = oi.order_item_status_cd LEFT JOIN sy_code cd_dc ON cd_dc.code_grp = 'COURIER' AND cd_dc.code_value = oi.dliv_courier_cd
ORDER BY oi.order_item_id ASC ORDER BY oi.order_item_id DESC ORDER BY oi.prod_nm ASC ORDER BY oi.prod_nm DESC ORDER BY oi.reg_date ASC ORDER BY oi.reg_date DESC ORDER BY oi.reg_date DESC
LIMIT #{p.limit} OFFSET #{p.offset}

mapper.update:
UPDATE od_order_item
order_item_status_cd = #{orderItemStatusCd}, order_item_status_cd_before = #{orderItemStatusCdBefore}, buy_confirm_yn = #{buyConfirmYn}, buy_confirm_date = #{buyConfirmDate}, settle_yn = #{settleYn}, settle_date = #{settleDate}, upd_by = #{updBy}, upd_date = #{updDate},
WHERE order_item_id = #{orderItemId}
